def amicable_numbers_sum(n):
    """Return the sum of all amicable numbers from 1 to n (inclusive)."""
    if n < 2:
        return 0

    # sum_div[i] will hold the sum of proper divisors of i
    sum_div = [0] * (n + 1)
    for i in range(1, n // 2 + 1):
        for j in range(i * 2, n + 1, i):
            sum_div[j] += i

    total = 0
    for a in range(2, n + 1):
        b = sum_div[a]
        if b != a and b <= n and sum_div[b] == a:
            total += a
    return total
