def reverse_vowels(s: str) -> str:
    vowels = "aeiouAEIOU"
    vowel_chars = [c for c in s if c in vowels]
    vowel_iter = iter(vowel_chars[::-1])
    result = []
    for ch in s:
        if ch in vowels:
            result.append(next(vowel_iter))
        else:
            result.append(ch)
    return ''.join(result)
